#include<bits/stdc++.h>
using namespace std;
int n,m,a[125],ans=0,vis[125][125];
const int MOD=1000007;
int dfs(int d,int w){
	if(w>m)return 0;
    if(w==m)return 1;
    if(d==n+1)return 0;
    if(vis[d][w])return vis[d][w];
	int ans=0;
	for(int i=0;i<=a[d];i++){
		ans+=dfs(d+1,w+i);
		ans%=MOD; 
	}
	vis[d][w]=ans;
	return ans;
}
int main(void){
    cin>>n>>m;
    for(int i=1;i<=n;i++)cin>>a[i];
    cout<<dfs(1,0);
    return false;
}
